extends Resource
class_name ItemData

@export var id: String = ""
@export var quantity: int = 0
@export var rarity: int = 0

extends Resource
class_name GameSaveData

@export var player_position: Vector2 = Vector2.ZERO
@export var inventory: Array[ItemData] = []
@export var unlocked_levels: PackedStringArray = PackedStringArray()
@export var last_played: int = 0

extends RefCounted
class_name SaveManager


func save_to_disk(data: GameSaveData, path: String, binary: bool) -> int:
	var normalized_path := _normalize_save_path(path, binary)
	return ResourceSaver.save(data, normalized_path)


func load_from_disk(path: String) -> GameSaveData:
	var load_path := _resolve_load_path(path)
	if load_path == "" or not FileAccess.file_exists(load_path):
		return null
	var resource = ResourceLoader.load(load_path)
	if resource is GameSaveData:
		return resource
	return null


func compute_hash(data: GameSaveData) -> String:
	var ctx := HashingContext.new()
	ctx.start(HashingContext.HASH_SHA256)

	# Hash player_position
	ctx.update(var_to_bytes(data.player_position))

	# Hash each inventory item's exported fields in order
	for item: ItemData in data.inventory:
		ctx.update(var_to_bytes(item.id))
		ctx.update(var_to_bytes(item.quantity))
		ctx.update(var_to_bytes(item.rarity))

	# Hash unlocked_levels
	ctx.update(var_to_bytes(data.unlocked_levels))

	# Hash last_played
	ctx.update(var_to_bytes(data.last_played))

	return ctx.finish().hex_encode().to_lower()


func _normalize_save_path(path: String, binary: bool) -> String:
	var ext := ".res" if binary else ".tres"
	if path.ends_with(".tres") or path.ends_with(".res"):
		return path.get_basename() + ext
	else:
		return path + ext


func _resolve_load_path(path: String) -> String:
	if path.ends_with(".tres"):
		# Prefer exact extension match, fall back to alternate
		if FileAccess.file_exists(path):
			return path
		var alt_path := path.get_basename() + ".res"
		if FileAccess.file_exists(alt_path):
			return alt_path
		return path
	elif path.ends_with(".res"):
		# Prefer exact extension match, fall back to alternate
		if FileAccess.file_exists(path):
			return path
		var alt_path := path.get_basename() + ".tres"
		if FileAccess.file_exists(alt_path):
			return alt_path
		return path
	else:
		# No extension provided — check both formats
		var tres_path := path + ".tres"
		var res_path := path + ".res"
		if FileAccess.file_exists(tres_path):
			return tres_path
		if FileAccess.file_exists(res_path):
			return res_path
		# Default to text format if neither exists yet
		return tres_path

extends SceneTree

func _init() -> void:
	var sm := SaveManager.new()

	# Create test data
	var item1 := ItemData.new()
	item1.id = "sword"
	item1.quantity = 1
	item1.rarity = 3

	var item2 := ItemData.new()
	item2.id = "potion"
	item2.quantity = 5
	item2.rarity = 1

	var save_data := GameSaveData.new()
	save_data.player_position = Vector2(100.5, 200.25)
	save_data.inventory = [item1, item2]
	save_data.unlocked_levels = PackedStringArray(["level_1", "level_2", "level_3"])
	save_data.last_played = 1717900000

	# Compute original hash
	var original_hash := sm.compute_hash(save_data)
	print("Original hash: ", original_hash)

	# Test .tres (text format) round-trip
	var tres_result := sm.save_to_disk(save_data, "user://test_save", false)
	print("Save .tres result: ", tres_result, " (expected 0 = OK)")

	var loaded_tres: GameSaveData = sm.load_from_disk("user://test_save.tres")
	if loaded_tres == null:
		print("ERROR: Failed to load .tres file")
	else:
		var tres_hash := sm.compute_hash(loaded_tres)
		print("Loaded .tres hash: ", tres_hash)
		print("Hashes match (.tres): ", original_hash == tres_hash)
		print("Player position match: ", loaded_tres.player_position == save_data.player_position)
		print("Inventory size match: ", loaded_tres.inventory.size() == save_data.inventory.size())
		if loaded_tres.inventory.size() >= 2:
			print("Item 0 match: ", loaded_tres.inventory[0].id == "sword" and loaded_tres.inventory[0].quantity == 1 and loaded_tres.inventory[0].rarity == 3)
			print("Item 1 match: ", loaded_tres.inventory[1].id == "potion" and loaded_tres.inventory[1].quantity == 5 and loaded_tres.inventory[1].rarity == 1)
		print("Unlocked levels match: ", loaded_tres.unlocked_levels == save_data.unlocked_levels)
		print("Last played match: ", loaded_tres.last_played == save_data.last_played)

	# Test .res (binary format) round-trip
	var res_result := sm.save_to_disk(save_data, "user://test_save", true)
	print("Save .res result: ", res_result, " (expected 0 = OK)")

	var loaded_res: GameSaveData = sm.load_from_disk("user://test_save.res")
	if loaded_res == null:
		print("ERROR: Failed to load .res file")
	else:
		var res_hash := sm.compute_hash(loaded_res)
		print("Loaded .res hash: ", res_hash)
		print("Hashes match (.res): ", original_hash == res_hash)
		print("Player position match: ", loaded_res.player_position == save_data.player_position)
		print("Inventory size match: ", loaded_res.inventory.size() == save_data.inventory.size())
		if loaded_res.inventory.size() >= 2:
			print("Item 0 match: ", loaded_res.inventory[0].id == "sword" and loaded_res.inventory[0].quantity == 1 and loaded_res.inventory[0].rarity == 3)
			print("Item 1 match: ", loaded_res.inventory[1].id == "potion" and loaded_res.inventory[1].quantity == 5 and loaded_res.inventory[1].rarity == 1)
		print("Unlocked levels match: ", loaded_res.unlocked_levels == save_data.unlocked_levels)
		print("Last played match: ", loaded_res.last_played == save_data.last_played)

	# Test path normalization: save with extension provided
	var res_result2 := sm.save_to_disk(save_data, "user://test_save2.tres", true)
	print("Save with .tres ext but binary=true result: ", res_result2, " (expected 0 = OK)")
	var loaded_res2: GameSaveData = sm.load_from_disk("user://test_save2.res")
	print("Load from .res after saving with .tres ext: ", loaded_res2 != null)

	# Test path normalization: load without extension
	var loaded_no_ext: GameSaveData = sm.load_from_disk("user://test_save")
	print("Load without extension: ", loaded_no_ext != null)

	print("\nAll tests completed.")
	quit()
